INSERT INTO dawah_articles (category_id, slug, title_ar, summary_ar, body_ar, tags, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='women-family'), 'women-in-islam',
'المرأة في الإسلام: الكرامة والحقوق كما وردت في النصوص',
'نظرة موضوعية لمكانة المرأة في الإسلام: الحقوق المالية والتعليمية والاجتماعية، ورد على تصورات شائعة خاطئة.',
'يقرر الإسلام مبدأً جوهريًا في التكوين الإنساني نفسه: المرأة والرجل متساويان في أصل الخلقة والكرامة الإنسانية والتكليف الديني والثواب والعقاب. القرآن ينص صراحة على أن الله خلق الناس "من نفس واحدة"، وأن الجزاء الأخروي معلَّق على العمل الصالح لا على الجنس: "مَنْ عَمِلَ صَالِحًا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَلَنُحْيِيَنَّهُ حَيَاةً طَيِّبَةً". على المستوى الحقوقي العملي، منح الإسلام المرأة، في سياق تاريخي سبق كثيرًا من الحضارات المعاصرة له بقرون: حق الملكية المستقلة والتصرف المالي الكامل بلا وصاية زوج أو أب، وحق الميراث المضمون نصًا (خلافًا لمجتمعات حرمتها الميراث كليًا)، وحق اختيار الزوج ورفض من لا ترضاه، وحق طلب الطلاق (الخلع) إن لم ترغب في استمرار الزواج، وحق طلب العلم فرضًا كالرجل تمامًا ("طلب العلم فريضة على كل مسلم ومسلمة"). أما مسألة تفاوت بعض الأحكام التفصيلية (كنصيب الميراث في حالات معينة، أو الشهادة في بعض المعاملات المالية)، فيرى الفقه الإسلامي أنها مرتبطة غالبًا بتوزيع مختلف للمسؤوليات المالية (كإلزام الرجل بالنفقة الكاملة على الأسرة بينما مال المرأة ملكها الخاص كليًا ولو عملت)، لا بتفاوت في القيمة الإنسانية أو الكرامة. هذه مسائل تفصيلية تستحق نقاشًا مستقلًا أعمق لمن أراد التفصيل، ونرحّب بالتواصل مع داعية لذلك.',
ARRAY['المرأة في الإسلام','الحقوق','المساواة'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='islamic-history'), 'how-islam-views-previous-prophets',
'كيف ينظر الإسلام إلى موسى وعيسى والأنبياء السابقين؟',
'الإيمان بكل الأنبياء السابقين ركن أساسي في عقيدة المسلم؛ كيف يفهم الإسلام العلاقة بين رسالته ورسالات من سبقه.',
'من أبرز ما يميّز عقيدة المسلم أن الإيمان بجميع الأنبياء السابقين — آدم ونوح وإبراهيم وإسماعيل وإسحاق ويعقوب وموسى وداود وسليمان وعيسى وغيرهم عليهم السلام — ركن أساسي لا يكتمل الإيمان بدونه؛ من أنكر نبيًا واحدًا منهم فقد أنكر الإيمان بالرسل جميعًا في التصور الإسلامي. القرآن يذكر كثيرًا من هؤلاء الأنبياء بالاسم، ويروي جوانب من قصصهم بتكريم وإجلال، ويصف عيسى عليه السلام بأوصاف عظيمة (كلمة الله، روح منه، المسيح) مع نفي ألوهيته. لا يرى الإسلام نفسه دينًا جديدًا منفصلًا عن هذا الإرث النبوي، بل استمرارًا له وختامًا لرسالته الواحدة: توحيد الله وحده. فما الذي تغيّر إذن؟ يرى الإسلام أن رسالات سابقة تعرّضت عبر قرون النقل البشري لتحريف أو تبديل في بعض تفاصيلها (وهذه دعوى تحتاج نقاشًا علميًا مفصَّلًا لا حسمًا مختصرًا)، وأن محمدًا ﷺ جاء ليجدّد الدعوة الأصلية نفسها ويختمها برسالة محفوظة موثَّقة موجَّهة لكل البشرية لا لأمة واحدة. هذا الموقف يجعل احترام الإسلام لموسى وعيسى عليهما السلام جزءًا أصيلًا من العقيدة الإسلامية نفسها، لا مجاملة دبلوماسية له.',
ARRAY['الأنبياء السابقون','موسى','عيسى','التصورات المقارنة'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='women-family'), 'family-and-marriage-in-islam',
'الأسرة والزواج في الإسلام: أساس المودة والرحمة',
'كيف ينظّم الإسلام العلاقة الزوجية والأسرية على أساس المودة والتراضي، لا التسلط أو الإكراه.',
'يصف القرآن العلاقة الزوجية بصورة شعرية عميقة: "وَمِنْ آيَاتِهِ أَنْ خَلَقَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَاجًا لِّتَسْكُنُوا إِلَيْهَا وَجَعَلَ بَيْنَكُم مَّوَدَّةً وَرَحْمَةً" — أساس الزواج في الإسلام هو السكينة النفسية والمودة والرحمة المتبادلة، لا مجرد عقد شكلي أو وظيفة اجتماعية. يقوم الزواج على التراضي الكامل من الطرفين (لا يصح إكراه أي منهما)، وعلى مهر تُلزَم به المرأة يُعطى لها هي شخصيًا وتتصرف فيه كيفما شاءت. يوصي الإسلام بحسن المعاشرة صراحة، وينهى نصًا عن الإضرار بالزوجة أو ظلمها، ويعتبر النبي ﷺ "خيركم خيركم لأهله". أما الطلاق، فهو مباح عند الحاجة الحقيقية لكنه "أبغض الحلال إلى الله" — أي مشروع كحل أخير لا مشجَّع عليه، مع تشريع فترات وخطوات تهدئة (كالعدة ومحاولات الإصلاح) قبل وقوعه النهائي. تجاه الأبناء، يرسّخ الإسلام مسؤولية مشتركة للوالدين تجاه تربيتهم وحقوقهم المالية والعاطفية، ويعتبر برّ الوالدين لاحقًا من أعظم القربات. هذا التصور الشامل يجعل الأسرة في الإسلام وحدة أخلاقية متكاملة، لا مجرد ترتيب قانوني.',
ARRAY['الزواج','الأسرة','المودة والرحمة'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='ethics'), 'work-wealth-ethics-in-islam',
'العمل والمال والأخلاق في الإسلام',
'كيف ينظّم الإسلام كسب المال وإنفاقه ضمن إطار أخلاقي يوازن بين السعي الدنيوي والمسؤولية الأخروية.',
'لا يرى الإسلام في العمل والسعي لكسب الرزق تعارضًا مع التديّن، بل يعتبر طلب الرزق الحلال عبادة في ذاتها إن اقترن بنية صالحة والتزام بالحلال. يشجّع الإسلام على العمل والإنتاج، وينهى عن الكسل والاتكال، ويعتبر "اليد العليا خير من اليد السفلى" (المعطي خير من الآخذ). في المقابل، يضع الإسلام قيودًا أخلاقية صارمة على طرق الكسب: تحريم الربا (الفائدة على القروض) لما فيه من استغلال محتمل للمحتاج، وتحريم الغش والاحتكار الضار والرشوة وأكل أموال الناس بالباطل، وإلزام الوفاء بالعقود والأمانات. أما إنفاق المال، فيوازن الإسلام بين حق النفس والأسرة في التمتع بالطيبات دون إسراف، وحق الفقراء والمحتاجين عبر الزكاة (فريضة سنوية منظَّمة، لا صدقة اختيارية فقط) والصدقات التطوعية. يُنظَر للمال في التصور الإسلامي كأمانة واستخلاف من الله لا ملكية مطلقة نهائية، وهذا يمنح جمع المال وإنفاقه بُعدًا أخلاقيًا مستمرًا يتجاوز مجرد التراكم المادي.',
ARRAY['المال','العمل','الزكاة','الأخلاق الاقتصادية'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='purpose-of-life'), 'islamic-view-of-death-and-purpose',
'الموت والغاية من الوجود في التصور الإسلامي',
'كيف يربط الإسلام بين تصوّر الموت والآخرة وبين إعطاء الحياة الدنيا معنى وغاية واضحة.',
'يطرح الإسلام إجابة متكاملة عن سؤال إنساني قديم: لماذا نحيا، وماذا يحدث حين نموت؟ الغاية من الخلق، كما يقررها القرآن، هي عبادة الله وحده بالمعنى الواسع للعبادة (كل عمل صالح بنية خالصة، لا الشعائر فقط): "وَمَا خَلَقْتُ الْجِنَّ وَالْإِنسَ إِلَّا لِيَعْبُدُونِ". هذه الغاية تمنح الحياة اتجاهًا واضحًا بدل شعور التيه أو العبثية الذي يشكو منه كثيرون في غياب أي غاية متعالية. أما الموت، فليس نهاية عدمية في التصور الإسلامي، بل انتقال إلى مرحلة برزخية ثم بعث وحساب عادل يوم القيامة، يُجازى فيه كل إنسان بما يستحق بدقة تامة، مهما دقّ العمل: "فَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ". هذا الامتداد الأبدي للمعنى يغيّر طريقة عيش الحياة الدنيا نفسها: كل عمل خير له قيمة باقية تتجاوز اللحظة الفانية، وكل ظلم واقع لا يذهب هدرًا مهما طال الزمن. لهذا يرى المسلم في الموت ليس نهاية مرعبة بلا معنى، بل عبورًا متوقَّعًا نحو عدل نهائي ومعنى أوسع بكثير من حدود العمر الدنيوي المحدود.',
ARRAY['الموت','الغاية من الوجود','الآخرة'], 'draft', false)
ON CONFLICT (slug) DO NOTHING;
